// MARK: - Keychain Manager

class KeychainManager {
    static let shared = KeychainManager()
    private let serviceIdentifier = "com.cryptowallet.keys"
    
    private init() {}
    
    func storePrivateKey(_ keyData: Data, forAddress address: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecAttrAccount as String: address,
            kSecValueData as String: keyData,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
            kSecAttrAccessControl as String: try createAccessControl()
        ]
        
        // Delete existing key if present
        SecItemDelete(query as CFDictionary)
        
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw WalletError.keychainError(status)
        }
    }
    
    func retrievePrivateKey(forAddress address: String) throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecAttrAccount as String: address,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            throw WalletError.keyNotFound
        }
        
        return data
    }
    
    func deletePrivateKey(forAddress address: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecAttrAccount as String: address
        ]
        
        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw WalletError.keychainError(status)
        }
    }
    
    func getAllStoredAddresses() throws -> [String] {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceIdentifier,
            kSecReturnAttributes as String: true,
            kSecMatchLimit as String: kSecMatchLimitAll
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        if status == errSecItemNotFound {
            return []
        }
        
        guard status == errSecSuccess, let items = result as? [[String: Any]] else {
            throw WalletError.keychainError(status)
        }
        
        return items.compactMap { $0[kSecAttrAccount as String] as? String }
    }
    
    private func createAccessControl() throws -> SecAccessControl {
        var error: Unmanaged<CFError>?
        guard let accessControl = SecAccessControlCreateWithFlags(
            kCFAllocatorDefault,
            kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
            .privateKeyUsage,
            &error
        ) else {
            // Fallback without biometric for simulator/devices without biometric
            guard let fallbackControl = SecAccessControlCreateWithFlags(
                kCFAllocatorDefault,
                kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
                [],
                &error
            ) else {
                throw WalletError.keyGenerationFailed
            }
            return fallbackControl
        }
        return accessControl
    }
}

// MARK: - Key Generation & Crypto

class CryptoEngine {
    static let shared = CryptoEngine()
    
    private init() {}
    
    struct KeyPair {
        let privateKey: Data
        let publicKey: Data
        let address: String
    }
    
    func generateKeyPair() throws -> KeyPair {
        let privateKey = P256.Signing.PrivateKey()
        let privateKeyData = privateKey.rawRepresentation
        let publicKeyData = privateKey.publicKey.rawRepresentation
        
        // Generate address from public key (similar to Ethereum-style)
        let address = generateAddress(from: publicKeyData)
        
        return KeyPair(
            privateKey: privateKeyData,
            publicKey: publicKeyData,
            address: address
        )
    }
    
    func generateDeterministicKeyPair(fromSeed seed: Data) throws -> KeyPair {
        // HKDF to derive key material from seed
        let symmetricKey = SymmetricKey(data: seed)
        let derivedKey = HKDF<SHA256>.deriveKey(
            inputKeyMaterial: symmetricKey,
            salt: "com.cryptowallet.keygen".data(using: .utf8)!,
            info: "wallet-key-derivation".data(using: .utf8)!,
            outputByteCount: 32
        )
        
        let keyData = derivedKey.withUnsafeBytes { Data($0) }
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: keyData)
        let publicKeyData = privateKey.publicKey.rawRepresentation
        let address = generateAddress(from: publicKeyData)
        
        return KeyPair(
            privateKey: keyData,
            publicKey: publicKeyData,
            address: address
        )
    }
    
    func generateAddress(from publicKey: Data) -> String {
        let hash = SHA256.hash(data: publicKey)
        let hashData = Data(hash)
        // Take last 20 bytes for address (Ethereum-style)
        let addressBytes = hashData.suffix(20)
        let checksumAddress = "0x" + addressBytes.map { String(format: "%02x", $0) }.joined()
        return checksumAddress
    }
    
    func signData(_ data: Data, withPrivateKey privateKeyData: Data) throws -> (signature: Data, r: Data, s: Data) {
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let signature = try privateKey.signature(for: data)
        let rawSignature = signature.rawRepresentation
        
        // Split into r and s components (each 32 bytes for P256)
        let r = rawSignature.prefix(32)
        let s = rawSignature.suffix(32)
        
        return (signature: rawSignature, r: Data(r), s: Data(s))
    }
    
    func verifySignature(_ signature: Data, for data: Data, publicKey publicKeyData: Data) -> Bool {
        guard let publicKey = try? P256.Signing.PublicKey(rawRepresentation: publicKeyData),
              let ecdsaSignature = try? P256.Signing.ECDSASignature(rawRepresentation: signature) else {
            return false
        }
        return publicKey.isValidSignature(ecdsaSignature, for: data)
    }
    
    func hashTransaction(_ transaction: Transaction) -> Data {
        let encoder = JSONEncoder()
        encoder.outputFormatting = .sortedKeys
        guard let data = try? encoder.encode(transaction) else {
            return Data()
        }
        let hash = SHA256.hash(data: data)
        return Data(hash)
    }
}

