// MARK: - Wallet Manager

class WalletManager {
    static let shared = WalletManager()
    
    private let keychainManager = KeychainManager.shared
    private let cryptoEngine = CryptoEngine.shared
    private let mnemonicGenerator = MnemonicGenerator.shared
    
    private let walletsKey = "stored_wallets"
    private let userDefaults = UserDefaults.standard
    
    private init() {}
    
    // MARK: - Wallet Creation
    
    func createWallet() throws -> (wallet: Wallet, mnemonic: [String]) {
        let mnemonic = mnemonicGenerator.generateMnemonic()
        let seed = mnemonicGenerator.mnemonicToSeed(mnemonic)
        let keyPair = try cryptoEngine.generateDeterministicKeyPair(fromSeed: seed)
        
        // Store private key in Keychain
        try keychainManager.storePrivateKey(keyPair.privateKey, forAddress: keyPair.address)
        
        let wallet = Wallet(
            address: keyPair.address,
            publicKey: keyPair.publicKey.hexEncodedString(),
            createdAt: Date()
        )
        
        // Store wallet metadata
        try storeWalletMetadata(wallet)
        
        return (wallet, mnemonic)
    }
    
    func importWallet(fromMnemonic mnemonic: [String], passphrase: String = "") throws -> Wallet {
        guard mnemonicGenerator.validateMnemonic(mnemonic) else {
            throw WalletError.keyGenerationFailed
        }
        
        let seed = mnemonicGenerator.mnemonicToSeed(mnemonic, passphrase: passphrase)
        let keyPair = try cryptoEngine.generateDeterministicKeyPair(fromSeed: seed)
        
        try keychainManager.storePrivateKey(keyPair.privateKey, forAddress: keyPair.address)
        
        let wallet = Wallet(
            address: keyPair.address,
            publicKey: keyPair.publicKey.hexEncodedString(),
            createdAt: Date()
        )
        
        try storeWalletMetadata(wallet)
        
        return wallet
    }
    
    func importWallet(fromPrivateKey privateKeyHex: String) throws -> Wallet {
        guard let privateKeyData = Data(hexString: privateKeyHex) else {
            throw WalletError.keyGenerationFailed
        }
        
        let privateKey = try P256.Signing.PrivateKey(rawRepresentation: privateKeyData)
        let publicKeyData = privateKey.publicKey.rawRepresentation
        let address = cryptoEngine.generateAddress(from: publicKeyData)
        
        try keychainManager.storePrivateKey(privateKeyData, forAddress: address)
        
        let wallet = Wallet(
            address: address,
            publicKey: publicKeyData.hexEncodedString(),
            createdAt: Date()
        )
        
        try storeWalletMetadata(wallet)
        
        return wallet
    }
    
    // MARK: - Transaction Signing
    
    func signTransaction(_ transaction: Transaction) throws -> SignedTransaction {
        let privateKeyData = try keychainManager.retrievePrivateKey(forAddress: transaction.from)
        let transactionHash = cryptoEngine.hashTransaction(transaction)
        
        let (signature, r, s) = try cryptoEngine.signData(transactionHash, withPrivateKey: privateKeyData)
        
        // Calculate v value (recovery id + chainId * 2 + 35 for EIP-155)
        let v = transaction.chainId * 2 + 35
        
        return SignedTransaction(
            transaction: transaction,
            signature: signature.hexEncodedString(),
            v: v,
            r: r.hexEncodedString(),
            s: s.hexEncodedString()
        )
    }
    
    func signMessage(_ message: String, withAddress address: String) throws -> String {
        let privateKeyData = try keychainManager.retrievePrivateKey(forAddress: address)
        
        // Prefix message (similar to Ethereum personal_sign)
        let prefix = "\u{19}Ethereum Signed Message:\n\(message.count)"
        let prefixedMessage = (prefix + message).data(using: .utf8)!
        let hash = SHA256.hash(data: prefixedMessage)
        
        let (signature, _, _) = try cryptoEngine.signData(Data(hash), withPrivateKey: privateKeyData)
        return signature.hexEncodedString()
    }
    
    // MARK: - Wallet Management
    
    func getWallets() -> [Wallet] {
        guard let data = userDefaults.data(forKey: walletsKey),
              let wallets = try? JSONDecoder().decode([Wallet].self, from: data) else {
            return []
        }
        return wallets
    }
    
    func deleteWallet(_ address: String) throws {
        try keychainManager.deletePrivateKey(forAddress: address)
        
        var wallets = getWallets()
        wallets.removeAll { $0.address == address }
        
        let data = try JSONEncoder().encode(wallets)
        userDefaults.set(data, forKey: walletsKey)
    }
    
    func validateAddress(_ address: String) -> Bool {
        // Basic validation: starts with 0x, 42 chars total, hex characters
        let hexPattern = "^0x[0-9a-fA-F]{40}$"
        return address.range(of: hexPattern, options: .regularExpression) != nil
    }
    
    private func storeWalletMetadata(_ wallet: Wallet) throws {
        var wallets = getWallets()
        wallets.removeAll { $0.address == wallet.address }
        wallets.append(wallet)
        
        let data = try JSONEncoder().encode(wallets)
        userDefaults.set(data, forKey: walletsKey)
    }
}

// MARK: - Blockchain Communication

class BlockchainService {
    static let shared = BlockchainService()
    
    private let session: URLSession
    private var rpcURL: URL
    private var chainId: Int
    
    struct RPCRequest: Codable {
        let jsonrpc: String
        let method: String
        let params: [AnyCodable]
        let id: Int
    }
    
    struct RPCResponse<T: Codable>: Codable {
        let jsonrpc: String
        let id: Int
        let result: T?
        let error: RPCError?
    }
    
    struct RPCError: Codable {
        let code: Int
        let message: String
    }
    
    init() {
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 30
        config.waitsForConnectivity = true
        self.session = URLSession(configuration: config)
        
        // Default to Ethereum mainnet (can be configured)
        self.rpcURL = URL(string: "https://eth-mainnet.g.alchemy.com/v2/demo")!
        self.chainId = 1
    }
    
    func configure(rpcURL: String, chainId: Int) {
        if let url = URL(string: rpcURL) {
            self.rpcURL = url
        }
        self.chainId = chainId
    }
    
    // MARK: - Balance
    
    func getBalance(address: String) async throws -> BlockchainBalance {
        let result: String = try await makeRPCCall(
            method: "eth_getBalance",
            params: [AnyCodable(address), AnyCodable("latest")]
        )
        
        let balanceWei = hexToDecimal(result)
        let balanceEth = balanceWei / pow(10, 18)
        
        return BlockchainBalance(
            address: address,
            balance: balanceEth,
            currency: "ETH"
        )
    }
    
    // MARK: - Transaction Count (Nonce)
    
    func getTransactionCount(address: String) async throws -> Int {
        let result: String = try await makeRPCCall(
            method: "eth_getTransactionCount",
            params: [AnyCodable(address), AnyCodable("latest")]
        )
        
        return Int(hexToDecimal(result).description) ?? 0
    }
    
    // MARK: - Gas Price
    
    func getGasPrice() async throws -> Decimal {
        let result: String = try await makeRPCCall(
            method: "eth_gasPrice",
            params: []
        )
        
        return hexToDecimal(result)
    }
    
    // MARK: - Estimate Gas
    
    func estimateGas(from: String, to: String, value: Decimal) async throws -> Int {
        let valueHex = decimalToHex(value * pow(10, 18))
        
        let txObj: [String: String] = [
            "from": from,
            "to": to,
            "value": valueHex
        ]
        
        let result: String = try await makeRPCCall(
            method: "eth_estimateGas",
            params: [AnyCodable(txObj)]
        )
        
        return Int(hexToDecimal(result).description) ?? 21000
    }
    
    // MARK: - Send Transaction
    
    func sendSignedTransaction(_ signedTx: SignedTransaction) async throws -> String {
        let rawTx = encodeSignedTransaction(signedTx)
        
        let result: String = try await makeRPCCall(
            method: "eth_sendRawTransaction",
            params: [AnyCodable(rawTx)]
        )
        
        return result
    }
    
    // MARK: - Transaction Receipt
    
    func getTransactionReceipt(txHash: String) async throws -> TransactionReceipt? {
        struct ReceiptResponse: Codable {
            let transactionHash: String
            let status: String
            let blockNumber: String?
            let gasUsed: String?
        }
        
        do {
            let result: ReceiptResponse = try await makeRPCCall(
                method: "eth_getTransactionReceipt",
                params: [AnyCodable(txHash)]
            )
            
            return TransactionReceipt(
                transactionHash: result.transactionHash,
                status: result.status == "0x1",
                blockNumber: result.blockNumber.flatMap { Int(hexToDecimal($0).description) },
                gasUsed: result.gasUsed.flatMap { Int(hexToDecimal($0).description) }
            )
        } catch {
            return nil
        }
    }
    
    // MARK: - Block Number
    
    func getBlockNumber() async throws -> Int {
        let result: String = try await makeRPCCall(
            method: "eth_blockNumber",
            params: []
        )
        
        return Int(hexToDecimal(result).description) ?? 0
    }
    
    // MARK: - Build & Send Transaction
    
    func buildAndSendTransaction(from: String, to: String, amountEth: Decimal) async throws -> String {
        guard WalletManager.shared.validateAddress(from),
              WalletManager.shared.validateAddress(to) else {
            throw WalletError.invalidAddress
        }
        
        let nonce = try await getTransactionCount(address: from)
        let gasPrice = try await getGasPrice()
        let gasLimit = try await estimateGas(from: from, to: to, value: amountEth)
        
        let transaction = Transaction(
            from: from,
            to: to,
            amount: amountEth,
            nonce: nonce,
            gasPrice: gasPrice,
            gasLimit: gasLimit,
            chainId: chainId,
            timestamp: Date()
        )
        
        let signedTx = try WalletManager.shared.signTransaction(transaction)
        let txHash = try await sendSignedTransaction(signedTx)
        
        return txHash
    }
    
    // MARK: - Private Helpers
    
    private func makeRPCCall<T: Codable>(method: String, params: [AnyCodable]) async throws -> T {
        let request = RPCRequest(
            jsonrpc: "2.0",
            method: method,
            params: params,
            id: Int.random(in: 1...999999)
        )
        
        var urlRequest = URLRequest(url: rpcURL)
        urlRequest.httpMethod = "POST"
        urlRequest.setValue("application/json", forHTTPHeaderField: "Content-Type")
        urlRequest.httpBody = try JSONEncoder().encode(request)
        
        let (data, response) = try await session.data(for: urlRequest)
        
        guard let httpResponse = response as? HTTPURLResponse,
              (200...299).contains(httpResponse.statusCode) else {
            throw WalletError.networkError("HTTP request failed")
        }
        
        let rpcResponse = try JSONDecoder().decode(RPCResponse<T>.self, from: data)
        
        if let error = rpcResponse.error {
            throw WalletError.networkError(error.message)
        }
        
        guard let result = rpcResponse.result else {
            throw WalletError.networkError("Empty response")
        }
        
        return result
    }
    
    private func encodeSignedTransaction(_ signedTx: SignedTransaction) -> String {
        // RLP-encode the signed transaction
        let tx = signedTx.transaction
        var components: [String] = []
        
        components.append(decimalToHex(Decimal(tx.nonce)))
        components.append(decimalToHex(tx.gasPrice))
        components.append(decimalToHex(Decimal(tx.gasLimit)))
        components.append(tx.to)
        components.append(decimalToHex(tx.amount * pow(10, 18)))
        components.append("0x") // data
        components.append(decimalToHex(Decimal(signedTx.v)))
        components.append("0x" + signedTx.r)
        components.append("0x" + signedTx.s)
        
        // Simplified encoding - real implementation would use proper RLP
        let encoded = components.joined(separator: "")
        let hash = encoded.data(using: .utf8)!.sha256()
        return "0x" + hash.hexEncodedString()
    }
    
    private func hexToDecimal(_ hex: String) -> Decimal {
        let cleanHex = hex.hasPrefix("0x") ? String(hex.dropFirst(2)) : hex
        guard let value = UInt64(cleanHex, radix: 16) else { return 0 }
        return Decimal(value)
    }
    
    private func decimalToHex(_ decimal: Decimal) -> String {
        let intValue = NSDecimalNumber(decimal: decimal).uint64Value
        return "0x" + String(intValue, radix: 16)
    }
}

// MARK: - AnyCodable Helper

struct AnyCodable: Codable {
    let value: Any
    
    init(_ value: Any) {
        self.value = value
    }
    
    init(from decoder: Decoder) throws {
        let container = try decoder.singleValueContainer()
        if let string = try? container.decode(String.self) {
            value = string
        } else if let int = try? container.decode(Int.self) {
            value = int
        } else if let double = try? container.decode(Double.self) {
            value = double
        } else if let bool = try? container.decode(Bool.self) {
            value = bool
        } else if let dict = try? container.decode([String: AnyCodable].self) {
            value = dict.mapValues { $0.value }
        } else if let array = try? container.decode([AnyCodable].self) {
            value = array.map { $0.value }
        } else {
            value = NSNull()
        }
    }
    
    func encode(to encoder: Encoder) throws {
        var container = encoder.singleValueContainer()
        if let string = value as? String {
            try container.encode(string)
        } else if let int = value as? Int {
            try container.encode(int)
        } else if let double = value as? Double {
            try container.encode(double)
        } else if let bool = value as? Bool {
            try container.encode(bool)
        } else if let dict = value as? [String: Any] {
            let codableDict = dict.mapValues { AnyCodable($0) }
            try container.encode(codableDict)
        } else if let array = value as? [Any] {
            let codableArray = array.map { AnyCodable($0) }
            try container.encode(codableArray)
        } else {
            try container.encodeNil()
        }
    }
}

// MARK: - Transaction History Manager

class TransactionHistoryManager {
    static let shared = TransactionHistoryManager()
    
    private let storageKey = "transaction_history"
    
    struct TransactionRecord: Codable {
        let hash: String
        let from: String
        let to: String
        let amount: Decimal
        let currency: String
        let timestamp: Date
        let status: TransactionStatus
        let gasUsed: Decimal?
        let gasCost: Decimal?
    }
    
    enum TransactionStatus: String, Codable {
        case pending
        case confirmed
        case failed
    }
    
    private init() {}
    
    func addTransaction(_ record: TransactionRecord) {
        var history = getHistory(for: record.from)
        history.insert(record, at: 0)
        saveHistory(history, for: record.from)
    }
    
    func getHistory(for address: String) -> [TransactionRecord] {
        let key = "\(storageKey)_\(address)"
        guard let data = UserDefaults.standard.data(forKey: key),
              let records = try? JSONDecoder().decode([TransactionRecord].self, from: data) else {
            return []
        }
        return records
    }
    
    func updateTransactionStatus(hash: String, address: String, status: TransactionStatus) {
        var history = getHistory(for: address)
        if let index = history.firstIndex(where: { $0.hash == hash }) {
            let old = history[index]
            history[index] = TransactionRecord(
                hash: old.hash,
                from: old.from,
                to: old.to,
                amount: old.amount,
                currency: old.currency,
                timestamp: old.timestamp,
                status: status,
                gasUsed: old.gasUsed,
                gasCost: old.gasCost
            )
            saveHistory(history, for: address)
        }
    }
    
    private func saveHistory(_ history: [TransactionRecord], for address: String) {
        let key = "\(storageKey)_\(address)"
        if let data = try? JSONEncoder().encode(history) {
            UserDefaults.standard.set(data, forKey: key)
        }
    }
}

// MARK: - Biometric Authentication

import LocalAuthentication

class BiometricAuthManager {
    static let shared = BiometricAuthManager()
    
    private init() {}
    
    enum BiometricType {
        case faceID
        case touchID
        case none
    }
    
    var biometricType: BiometricType {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return .none
        }
        
        switch context.biometryType {
        case .faceID: return .faceID
        case .touchID: return .touchID
        default: return .none
        }
    }
    
    func authenticate(reason: String) async throws -> Bool {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            // Fall back to passcode
            guard context.canEvaluatePolicy(.deviceOwnerAuthentication, error: &error) else {
                throw WalletError.biometricAuthFailed
            }
            return try await context.evaluatePolicy(.deviceOwnerAuthentication, localizedReason: reason)
        }
        
        return try await context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason)
    }
}

// MARK: - Extensions

extension String {
    func sha256Hash() -> String {
        guard let data = self.data(using: .utf8) else { return "" }
        let hash = SHA256.hash(data: data)
        return hash.compactMap { String(format: "%02x", $0) }.joined()
    }
}

extension Data {
    func hexEncodedString() -> String {
        return map { String(format: "%02x", $0) }.joined()
    }
    
    init?(hexString: String) {
        let hex = hexString.hasPrefix("0x") ? String(hexString.dropFirst(2)) : hexString
        let len = hex.count / 2
        var data = Data(capacity: len)
        var index = hex.startIndex
        for _ in 0..<len {
            let nextIndex = hex.index(index, offsetBy: 2)
            if let byte = UInt8(hex[index..<nextIndex], radix: 16) {
                data.append(byte)
            } else {
                return nil
            }
            index = nextIndex
        }
        self = data
    }
    
    func sha256() -> Data {
        let hash = SHA256.hash(data: self)
        return Data(hash)
    }
}

