        return ai
    }()
    
    // MARK: - Lifecycle
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Crypto Wallet"
        view.backgroundColor = .systemBackground
        setupUI()
        loadExistingWallet()
    }
    
    // MARK: - UI Setup
    
    private func setupUI() {
        view.addSubview(scrollView)
        scrollView.addSubview(contentStack)
        
        // Wallet Card
        let cardStack = UIStackView(arrangedSubviews: [balanceLabel, addressLabel])
        cardStack.axis = .vertical
        cardStack.spacing = 8
        cardStack.translatesAutoresizingMaskIntoConstraints = false
        walletCard.addSubview(cardStack)
        
        contentStack.addArrangedSubview(walletCard)
        contentStack.addArrangedSubview(createWalletButton)
        contentStack.addArrangedSubview(importWalletButton)
        contentStack.addArrangedSubview(sendButton)
        contentStack.addArrangedSubview(refreshButton)
        contentStack.addArrangedSubview(signMessageButton)
        contentStack.addArrangedSubview(historyButton)
        
        view.addSubview(activityIndicator)
        
        NSLayoutConstraint.activate([
            scrollView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            scrollView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            scrollView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            scrollView.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor),
            
            contentStack.topAnchor.constraint(equalTo: scrollView.topAnchor),
            contentStack.leadingAnchor.constraint(equalTo: scrollView.leadingAnchor),
            contentStack.trailingAnchor.constraint(equalTo: scrollView.trailingAnchor),
            contentStack.bottomAnchor.constraint(equalTo: scrollView.bottomAnchor),
            contentStack.widthAnchor.constraint(equalTo: scrollView.widthAnchor),
            
            walletCard.heightAnchor.constraint(equalToConstant: 180),
            
            cardStack.centerXAnchor.constraint(equalTo: walletCard.centerXAnchor),
            cardStack.centerYAnchor.constraint(equalTo: walletCard.centerYAnchor),
            cardStack.leadingAnchor.constraint(greaterThanOrEqualTo: walletCard.leadingAnchor, constant: 20),
            cardStack.trailingAnchor.constraint(lessThanOrEqualTo: walletCard.trailingAnchor, constant: -20),
            
            activityIndicator.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            activityIndicator.centerYAnchor.constraint(equalTo: view.centerYAnchor),
        ])
        
        updateUIState()
    }
    
    private func updateUIState() {
        let hasWallet = currentWallet != nil
        sendButton.isEnabled = hasWallet
        sendButton.alpha = hasWallet ? 1.0 : 0.5
        refreshButton.isEnabled = hasWallet
        refreshButton.alpha = hasWallet ? 1.0 : 0.5
        signMessageButton.isEnabled = hasWallet
        signMessageButton.alpha = hasWallet ? 1.0 : 0.5
        historyButton.isEnabled = hasWallet
        historyButton.alpha = hasWallet ? 1.0 : 0.5
        
        if let wallet = currentWallet {
            addressLabel.text = wallet.address
            if let balance = balance {
                balanceLabel.text = "\(balance.balance) \(balance.currency)"
            }
        } else {
            addressLabel.text = "No Wallet"
            balanceLabel.text = "0.0000 ETH"
        }
    }
    
    private func loadExistingWallet() {
        let wallets = walletManager.getWallets()
        if let firstWallet = wallets.first {
            currentWallet = firstWallet
            updateUIState()
            refreshBalance()
        }
    }
    
    // MARK: - Actions
    
    @objc private func createWalletTapped() {
        do {
            let (wallet, mnemonic) = try walletManager.createWallet()
            currentWallet = wallet
            updateUIState()
            
            showMnemonicAlert(mnemonic)
            refreshBalance()
        } catch {
            showError(error)
        }
    }
    
    @objc private func importWalletTapped() {
        let alert = UIAlertController(title: "Import Wallet", message: "Enter your 12-word recovery phrase (space separated)", preferredStyle: .alert)
        alert.addTextField { textField in
            textField.placeholder = "word1 word2 word3 ... word12"
            textField.autocapitalizationType = .none
            textField.autocorrectionType = .no
        }
        
        alert.addAction(UIAlertAction(title: "Import", style: .default) { [weak self] _ in
            guard let mnemonicString = alert.textFields?.first?.text else { return }
            let words = mnemonicString.split(separator: " ").map(String.init)
            
            do {
                let wallet = try self?.walletManager.importWallet(fromMnemonic: words)
                self?.currentWallet = wallet
                self?.updateUIState()
                self?.refreshBalance()
                
                self?.showAlert(title: "Success", message: "Wallet imported successfully!\nAddress: \(wallet?.address ?? "")")
            } catch {
                self?.showError(error)
            }
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    @objc private func sendTapped() {
        guard let wallet = currentWallet else { return }
        
        Task {
            do {
                let authenticated = try await biometricAuth.authenticate(reason: "Authenticate to send transaction")
                guard authenticated else { return }
                
                await MainActor.run {
                    showSendDialog(fromAddress: wallet.address)
                }
            } catch {
                await MainActor.run {
                    // Fallback: show send dialog without biometric
                    showSendDialog(fromAddress: wallet.address)
                }
            }
        }
    }
    
    @objc private func refreshTapped() {
        refreshBalance()
    }
    
    @objc private func historyTapped() {
        guard let wallet = currentWallet else { return }
        let historyVC = TransactionHistoryViewController(address: wallet.address)
        navigationController?.pushViewController(historyVC, animated: true)
    }
    
    @objc private func signMessageTapped() {
        guard let wallet = currentWallet else { return }
        
        let alert = UIAlertController(title: "Sign Message", message: "Enter a message to sign", preferredStyle: .alert)
        alert.addTextField { textField in
            textField.placeholder = "Message to sign"
        }
        
        alert.addAction(UIAlertAction(title: "Sign", style: .default) { [weak self] _ in
            guard let message = alert.textFields?.first?.text, !message.isEmpty else { return }
            
            do {
                let signature = try self?.walletManager.signMessage(message, withAddress: wallet.address)
                self?.showAlert(title: "Signature", message: "Message signed!\n\nSignature:\n\(signature ?? "")")
            } catch {
                self?.showError(error)
            }
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    // MARK: - Helpers
    
    private func refreshBalance() {
        guard let wallet = currentWallet else { return }
        
        activityIndicator.startAnimating()
        
        Task {
            do {
                let balance = try await blockchainService.getBalance(address: wallet.address)
                await MainActor.run {
                    self.balance = balance
                    self.updateUIState()
                    self.activityIndicator.stopAnimating()
                }
            } catch {
                await MainActor.run {
                    self.activityIndicator.stopAnimating()
                    // Don't show error for balance refresh - just show 0
                    self.balanceLabel.text = "0.0000 ETH"
                }
            }
        }
    }
    
    private func showSendDialog(fromAddress: String) {
        let alert = UIAlertController(title: "Send ETH", message: "Enter recipient address and amount", preferredStyle: .alert)
        
        alert.addTextField { textField in
            textField.placeholder = "Recipient address (0x...)"
            textField.autocapitalizationType = .none
            textField.autocorrectionType = .no
        }
        
        alert.addTextField { textField in
            textField.placeholder = "Amount (ETH)"
            textField.keyboardType = .decimalPad
        }
        
        alert.addAction(UIAlertAction(title: "Send", style: .default) { [weak self] _ in
            guard let toAddress = alert.textFields?[0].text,
                  let amountString = alert.textFields?[1].text,
                  let amount = Decimal(string: amountString) else {
                self?.showAlert(title: "Error", message: "Invalid input")
                return
            }
            
            self?.executeSend(from: fromAddress, to: toAddress, amount: amount)
        })
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    private func executeSend(from: String, to: String, amount: Decimal) {
        activityIndicator.startAnimating()
        
        Task {
            do {
                let txHash = try await blockchainService.buildAndSendTransaction(
                    from: from,
                    to: to,
                    amountEth: amount
                )
                
                // Record transaction
                let record = TransactionHistoryManager.TransactionRecord(
                    hash: txHash,
                    from: from,
                    to: to,
                    amount: amount,
                    currency: "ETH",
                    timestamp: Date(),
                    status: .pending,
                    gasUsed: nil,
                    gasCost: nil
                )
                TransactionHistoryManager.shared.addTransaction(record)
                
                await MainActor.run {
                    self.activityIndicator.stopAnimating()
                    self.showAlert(title: "Success", message: "Transaction sent!\n\nHash: \(txHash)")
                    self.refreshBalance()
                }
            } catch {
                await MainActor.run {
                    self.activityIndicator.stopAnimating()
                    self.showError(error)
                }
            }
        }
    }
    
    private func showMnemonicAlert(_ mnemonic: [String]) {
        let words = mnemonic.enumerated().map { "\($0.offset + 1). \($0.element)" }.joined(separator: "\n")
        
        let alert = UIAlertController(
            title: "⚠️ Backup Your Recovery Phrase",
            message: "Write down these 12 words in order. This is the ONLY way to recover your wallet.\n\n\(words)",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Copy to Clipboard", style: .default) { _ in
            UIPasteboard.general.string = mnemonic.joined(separator: " ")
        })
        
        alert.addAction(UIAlertAction(title: "I've Saved It", style: .default) { [weak self] _ in
            self?.showAlert(title: "Wallet Created!", message: "Address: \(self?.currentWallet?.address ?? "")")
        })
        
        present(alert, animated: true)
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    private func showError(_ error: Error) {
        showAlert(title: "Error", message: error.localizedDescription)
    }
}

// MARK: - Transaction History View Controller

class TransactionHistoryViewController: UITableViewController {
    
    private let address: String
    private var transactions: [TransactionHistoryManager.TransactionRecord] = []
    
    init(address: String) {
        self.address = address
        super.init(style: .insetGrouped)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Transaction History"
        tableView.register(TransactionCell.self, forCellReuseIdentifier: "TransactionCell")
        loadTransactions()
    }
    
    private func loadTransactions() {
        transactions = TransactionHistoryManager.shared.getHistory(for: address)
        tableView.reloadData()
    }
    
    override func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return transactions.count
    }
    
    override func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "TransactionCell", for: indexPath) as! TransactionCell
        let tx = transactions[indexPath.row]
        cell.configure(with: tx, currentAddress: address)
        return cell
    }
    
    override func tableView(_ tableView: UITableView, heightForRowAt indexPath: IndexPath) -> CGFloat {
        return 80
    }
    
    override func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        let tx = transactions[indexPath.row]
        
        let alert = UIAlertController(title: "Transaction Details", message: """
        Hash: \(tx.hash)
        From: \(tx.from)
        To: \(tx.to)
        Amount: \(tx.amount) \(tx.currency)
        Status: \(tx.status.rawValue)
        Date: \(tx.timestamp)
        """, preferredStyle: .alert)
        
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

