        statusLabel.font = .systemFont(ofSize: 12)
        
        NSLayoutConstraint.activate([
            leftStack.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            leftStack.centerYAnchor.constraint(equalTo: contentView.centerYAnchor),
            leftStack.trailingAnchor.constraint(lessThanOrEqualTo: rightStack.leadingAnchor, constant: -8),
            
            rightStack.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            rightStack.centerYAnchor.constraint(equalTo: contentView.centerYAnchor),
        ])
    }
    
    func configure(with tx: TransactionHistoryManager.TransactionRecord, currentAddress: String) {
        let isSend = tx.from.lowercased() == currentAddress.lowercased()
        directionLabel.text = isSend ? "↑ Sent" : "↓ Received"
        directionLabel.textColor = isSend ? .systemRed : .systemGreen
        
        addressLabel.text = isSend ? "To: \(tx.to)" : "From: \(tx.from)"
        amountLabel.text = "\(isSend ? "-" : "+")\(tx.amount) \(tx.currency)"
        amountLabel.textColor = isSend ? .systemRed : .systemGreen
        
        let formatter = DateFormatter()
        formatter.dateStyle = .short
        formatter.timeStyle = .short
        dateLabel.text = formatter.string(from: tx.timestamp)
        
        switch tx.status {
        case .pending:
            statusLabel.text = "⏳ Pending"
            statusLabel.textColor = .systemOrange
        case .confirmed:
            statusLabel.text = "✅ Confirmed"
            statusLabel.textColor = .systemGreen
        case .failed:
            statusLabel.text = "❌ Failed"
            statusLabel.textColor = .systemRed
        }
    }
}

